import { type TextField } from "../forms";
import { msg } from '@lit/localize'

export const validators = {
    pesel: function(value: string) {
        value = value.trim();

        if (!/^\d*$/.test(value)) return msg("Wprowadzono znaki inne niż cyfry.");
        if (value.length != 11) return msg("Nieprawidłowa długość numeru PESEL.");

        const weights = [1, 3, 7, 9, 1, 3, 7, 9, 1, 3, 1];
        const sum = weights
            .map((val, idx) => val * parseInt(value[idx]))
            .reduce((a, b) => a + b);
        if (sum % 10 == 0) return '';
        else return msg("Nieprawidłowy numer PESEL.");
    },
    nip: function(value: string) {
        value = value.trim().split('-').join('');
        if (!/^\d*$/.test(value)) return msg('Wprowadzono znaki inne niż cyfry i "-".');
        if (value.length != 10) return msg("Nieprawidłowa długość numeru NIP.");

        const weights = [6, 5, 7, 2, 3, 4, 5, 6, 7, -1];
        const sum = weights
            .map((val, idx) => val * parseInt(value[idx]))
            .reduce((a, b) => a + b);
        if (sum % 11 == 0) return '';
        else return msg("Nieprawidłowy numer NIP.");
    }
};

type ValidatorName = keyof typeof validators;

function _applyValidators(textField: TextField, validatorNames: ValidatorName[]) {
    textField.addEventListener('change', function(){
        textField.setCustomValidity(
            textField.value // do not validate empty value, only required attribute should be used
                ? validatorNames
                    .map((validatorName) => validators[validatorName](textField.value))
                    .filter(err => err != '')
                    .join(' ')
                : ''
            );
    });
}

export function applyValidators(textField: TextField) {
    const validValidatorNames = textField.uiValidators.toLowerCase().split(' ')
        .filter((validatorName) => validators.hasOwnProperty(validatorName)) as ValidatorName[];
    _applyValidators(textField, validValidatorNames);

}
